"""
Parameterized generator for GH312_ceph-csi_5149.

Source PR:    https://github.com/ceph/ceph-csi/pull/5149
Source Issue: N/A

Seed varies: renames 'annotations' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH312_ceph-csi_5149'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH312_ceph-csi_5149'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('annotations', 'annotations' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH312_ceph-csi_5149',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ceph/ceph-csi',
                "pr_number": 5149,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ceph/ceph-csi/pull/5149",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'PendingReleaseNotes.md': '# v3.13 Pending Release Notes\n\n## Breaking Changes\n\n## Features\n\n- util: a log message "Slow GRPC" is now emitted when\n  CSI GRPC call outlives its deadline [PR](https://github.com/ceph/ceph-csi/pull/4847)\n- CSI metrics for sidecars are now exposed at `POD_IP`:`SIDECAR_ENDPOINT`/`metrics`\n  path. Check sidecar container spec for `SIDECAR_ENDPOINT`\n  value [PR](https://github.com/ceph/ceph-csi/pull/4887)\n- cephfs: support omap data store in radosnamespace [PR](https://github.com/ceph/ceph-csi/pull/4661)\n- helm: Support setting nodepluigin and provisioner annotations\n\n## NOTE\n',
            'internal/kms/dummy.go': '/*\nCopyright 2022 The Ceph-CSI Authors.\nLicensed under the Apache License, Version 2.0 (the "License");\nyou may not use this file except in compliance with the License.\nYou may obtain a copy of the License at\n    http://www.apache.org/licenses/LICENSE-2.0\nUnless required by applicable law or agreed to in writing, software\ndistributed under the License is distributed on an "AS IS" BASIS,\nWITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\nSee the License for the specific language governing permissions and\nlimitations under the License.\n*/\n\npackage kms\n\nimport "encoding/base64"\n\ntype TestDummyFunc func() EncryptionKMS\n\ntype ProviderTest struct {\n\tUniqueID        string\n\tCreateTestDummy TestDummyFunc\n}\n\ntype kmsTestProviderList struct {\n\tproviders map[string]ProviderTest\n}\n\nvar kmsTestManager = kmsTestProviderList{providers: map[string]ProviderTest{}}\n\nfunc RegisterTestProvider(provider ProviderTest) bool {\n\tkmsTestManager.providers[provider.UniqueID] = provider\n\n\treturn true\n}\n\nfunc GetKMSTestDummy(kmsID string) EncryptionKMS {\n\tprovider, ok := kmsTestManager.providers[kmsID]\n\tif !ok {\n\t\treturn nil\n\t}\n\n\treturn provider.CreateTestDummy()\n}\n\nfunc GetKMSTestProvider() map[string]ProviderTest {\n\treturn kmsTestManager.providers\n}\n\nfunc newDefaultTestDummy() EncryptionKMS {\n\treturn secretsKMS{passphrase: base64.URLEncoding.EncodeToString(\n\t\t[]byte("test dummy passphrase"))}\n}\n\nfunc newSecretsMetadataTestDummy() EncryptionKMS {\n\tsmKMS := secretsMetadataKMS{}\n\tsmKMS.secretsKMS = secretsKMS{passphrase: base64.URLEncoding.EncodeToString(\n\t\t[]byte("test dummy passphrase"))}\n\n\treturn smKMS\n}\n\nvar _ = RegisterTestProvider(ProviderTest{\n\tUniqueID:        kmsTypeSecretsMetadata,\n\tCreateTestDummy: newSecretsMetadataTestDummy,\n})\n\nvar _ = RegisterTestProvider(ProviderTest{\n\tUniqueID:        DefaultKMSType,\n\tCreateTestDummy: newDefaultTestDummy,\n})\n',
            'internal/kms/secretskms.go': '/*\nCopyright 2019 The Ceph-CSI Authors.\n\nLicensed under the Apache License, Version 2.0 (the "License");\nyou may not use this file except in compliance with the License.\nYou may obtain a copy of the License at\n\n    http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing, software\ndistributed under the License is distributed on an "AS IS" BASIS,\nWITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\nSee the License for the specific language governing permissions and\nlimitations under the License.\n*/\n\npackage kms\n\nimport (\n\t"context"\n\t"crypto/aes"\n\t"crypto/cipher"\n\t"crypto/rand"\n\t"encoding/json"\n\t"errors"\n\t"fmt"\n\t"io"\n\n\t"github.com/ceph/ceph-csi/internal/util/k8s"\n\n\t"golang.org/x/crypto/scrypt"\n\tmetav1 "k8s.io/apimachinery/pkg/apis/meta/v1"\n)\n\nconst (\n\t// Encryption passphrase location in K8s secrets.\n\tencryptionPassphraseKey = "encryptionPassphrase"\n\n\t// kmsTypeSecretsMetadata is the secretKMS with per-volume encryption,\n\t// where the DEK is stored in the metadata of the volume itself.\n\tkmsTypeSecretsMetadata = "metadata"\n\n\t// metadataSecretNameKey contains the key which corresponds to the\n\t// kubernetes secret name from where encryptionPassphrase is feteched.\n\tmetadataSecretNameKey = "secretName"\n\t// metadataSecretNamespaceKey contains the key which corresponds to the\n\t// kubernetes secret namespace from where encryptionPassphrase is feteched.\n\tmetadataSecretNamespaceKey = "secretNamespace"\n)\n\n// secretsKMS is default KMS implementation that means no KMS is in use.\ntype secretsKMS struct {\n\tintegratedDEK\n\n\tpassphrase string\n}\n\nvar _ = RegisterProvider(Provider{\n\tUniqueID:    DefaultKMSType,\n\tInitializer: newSecretsKMS,\n})\n\n// newSecretsKMS initializes a secretsKMS that uses the passphrase from the\n// secret that is configured for the StorageClass. This KMS provider uses a\n// single (LUKS) passhprase for all volumes.\nfunc newSecretsKMS(args ProviderInitArgs) (EncryptionKMS, error) {\n\tpassphraseValue, ok := args.Secrets[encryptionPassphraseKey]\n\tif !ok {\n\t\treturn nil, errors.New("missing encryption passphrase in secrets")\n\t}\n\n\treturn secretsKMS{passphrase: passphraseValue}, nil\n}\n\n// Destroy frees all used resources.\nfunc (kms secretsKMS) Destroy() {\n\t// nothing to do\n}\n\n// FetchDEK returns passphrase from Kubernetes secrets.\nfunc (kms secretsKMS) FetchDEK(ctx context.Context, key string) (string, error) {\n\treturn kms.passphrase, nil\n}\n\n// StoreDEK does nothing, as there is no passphrase per key (volume), so\n// no need to store is anywhere.\nfunc (kms secretsKMS) StoreDEK(ctx context.Context, key, value string) error {\n\treturn nil\n}\n\n// RemoveDEK is doing nothing as no new passphrases are saved with\n// secretsKMS.\nfunc (kms secretsKMS) RemoveDEK(ctx context.Context, key string) error {\n\treturn nil\n}\n\n// secretsMetadataKMS is a KMS based on the secretKMS, but stores the\n// Data-Encryption-Key (DEK) in the metadata of the volume.\ntype secretsMetadataKMS struct {\n\tsecretsKMS\n}\n\nvar _ = RegisterProvider(Provider{\n\tUniqueID:    kmsTypeSecretsMetadata,\n\tInitializer: initSecretsMetadataKMS,\n})\n\n// initSecretsMetadataKMS initializes a secretsMetadataKMS that wraps a secretKMS,\n// so that the passphrase from the user provided or StorageClass secrets can be used\n// for encrypting/decrypting DEKs that are stored in a detached DEKStore.\nfunc initSecretsMetadataKMS(args ProviderInitArgs) (EncryptionKMS, error) {\n\tvar (\n\t\tsmKMS                secretsMetadataKMS\n\t\tencryptionPassphrase string\n\t\tok                   bool\n\t\terr                  error\n\t)\n\n\tencryptionPassphrase, err = smKMS.fetchEncryptionPassphrase(\n\t\targs.Config, args.Tenant)\n\tif err != nil {\n\t\tif !errors.Is(err, errConfigOptionMissing) {\n\t\t\treturn nil, err\n\t\t}\n\t\t// if \'userSecret\' option is not specified, fetch encryptionPassphrase\n\t\t// from storageclass secrets.\n\t\tencryptionPassphrase, ok = args.Secrets[encryptionPassphraseKey]\n\t\tif !ok {\n\t\t\treturn nil, fmt.Errorf(\n\t\t\t\t"missing %q in storageclass secret", encryptionPassphraseKey)\n\t\t}\n\t}\n\tsmKMS.secretsKMS = secretsKMS{passphrase: encryptionPassphrase}\n\n\treturn smKMS, nil\n}\n\n// fetchEncryptionPassphrase fetches encryptionPassphrase from user provided secret.\nfunc (kms secretsMetadataKMS) fetchEncryptionPassphrase(\n\tconfig map[string]interface{},\n\tdefaultNamespace string,\n) (string, error) {\n\tvar (\n\t\tsecretName      string\n\t\tsecretNamespace string\n\t)\n\n\terr := setConfigString(&secretName, config, metadataSecretNameKey)\n\tif err != nil {\n\t\treturn "", err\n\t}\n\n\terr = setConfigString(&secretNamespace, config, metadataSecretNamespaceKey)\n\tif err != nil {\n\t\tif !errors.Is(err, errConfigOptionMissing) {\n\t\t\treturn "", err\n\t\t}\n\t\t// if \'secretNamespace\' option is not specified, defaults to namespace in\n\t\t// which PVC was created\n\t\tsecretNamespace = defaultNamespace\n\t}\n\n\tc, err := k8s.NewK8sClient()\n\tif err != nil {\n\t\treturn "", fmt.Errorf("can not get Secret %s/%s, failed to "+\n\t\t\t"connect to Kubernetes: %w", secretNamespace, secretName, err)\n\t}\n\n\tsecret, err := c.CoreV1().Secrets(secretNamespace).Get(context.TODO(),\n\t\tsecretName, metav1.GetOptions{})\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to get Secret %s/%s: %w",\n\t\t\tsecretNamespace, secretName, err)\n\t}\n\n\tpassphraseValue, ok := secret.Data[encryptionPassphraseKey]\n\tif !ok {\n\t\treturn "", fmt.Errorf("missing %q in Secret %s/%s",\n\t\t\tencryptionPassphraseKey, secretNamespace, secretName)\n\t}\n\n\treturn string(passphraseValue), nil\n}\n\n// Destroy frees all used resources.\nfunc (kms secretsMetadataKMS) Destroy() {\n\tkms.secretsKMS.Destroy()\n}\n\nfunc (kms secretsMetadataKMS) RequiresDEKStore() DEKStoreType {\n\treturn DEKStoreMetadata\n}\n\n// encryptedMetedataDEK contains the encrypted DEK and the Nonce that was used\n// during encryption. This structure is stored (in JSON format) in the DEKStore\n// that is linked to this KMS provider.\ntype encryptedMetedataDEK struct {\n\t// DEK is the encrypted data-encryption-key for the volume.\n\tDEK []byte `json:"dek"`\n\t// Nonce is a random byte slice to guarantee the uniqueness of the\n\t// encrypted DEK.\n\tNonce []byte `json:"nonce"`\n}\n\n// EncryptDEK encrypts the plainDEK with a key derived from the passphrase from\n// the secretsKMS and the volumeID.\n// The resulting encryptedDEK contains a JSON with the encrypted DEK and the\n// nonce that was used for encrypting.\nfunc (kms secretsMetadataKMS) EncryptDEK(ctx context.Context, volumeID, plainDEK string) (string, error) {\n\t// use the passphrase from the secretKMS\n\tpassphrase, err := kms.secretsKMS.FetchDEK(ctx, volumeID)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to get passphrase: %w", err)\n\t}\n\n\taead, err := generateCipher(passphrase, volumeID)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to generate cipher: %w", err)\n\t}\n\n\temd := encryptedMetedataDEK{}\n\temd.Nonce, err = generateNonce(aead.NonceSize())\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to generated nonce: %w", err)\n\t}\n\temd.DEK = aead.Seal(nil, emd.Nonce, []byte(plainDEK), nil)\n\n\temdData, err := json.Marshal(&emd)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to convert "+\n\t\t\t"encryptedMetedataDEK to JSON: %w", err)\n\t}\n\n\treturn string(emdData), nil\n}\n\n// DecryptDEK takes the JSON formatted `encryptedMetadataDEK` contents, and it\n// fetches secretKMS passphrase to decrypt the DEK.\nfunc (kms secretsMetadataKMS) DecryptDEK(ctx context.Context, volumeID, encryptedDEK string) (string, error) {\n\t// use the passphrase from the secretKMS\n\tpassphrase, err := kms.secretsKMS.FetchDEK(ctx, volumeID)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to get passphrase: %w", err)\n\t}\n\n\taead, err := generateCipher(passphrase, volumeID)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to generate cipher: %w", err)\n\t}\n\n\temd := encryptedMetedataDEK{}\n\terr = json.Unmarshal([]byte(encryptedDEK), &emd)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to convert data to "+\n\t\t\t"encryptedMetedataDEK: %w", err)\n\t}\n\n\tdek, err := aead.Open(nil, emd.Nonce, emd.DEK, nil)\n\tif err != nil {\n\t\treturn "", fmt.Errorf("failed to decrypt DEK: %w", err)\n\t}\n\n\treturn string(dek), nil\n}\n\nfunc (kms secretsMetadataKMS) GetSecret(ctx context.Context, volumeID string) (string, error) {\n\t// use the passphrase from the secretKMS\n\treturn kms.secretsKMS.FetchDEK(ctx, volumeID)\n}\n\n// generateCipher returns a AEAD cipher based on a passphrase and salt\n// (volumeID). The cipher can then be used to encrypt/decrypt the DEK.\nfunc generateCipher(passphrase, salt string) (cipher.AEAD, error) {\n\tkey, err := scrypt.Key([]byte(passphrase), []byte(salt), 32768, 8, 1, 32)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\tblockCipher, err := aes.NewCipher(key)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\taead, err := cipher.NewGCM(blockCipher)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\n\treturn aead, nil\n}\n\n// generateNonce returns a byte slice with random contents.\nfunc generateNonce(size int) ([]byte, error) {\n\tnonce := make([]byte, size)\n\tif _, err := io.ReadFull(rand.Reader, nonce); err != nil {\n\t\treturn nil, err\n\t}\n\n\treturn nonce, nil\n}\n',
            'internal/kms/secretskms_test.go': '/*\nCopyright 2021 The Ceph-CSI Authors.\n\nLicensed under the Apache License, Version 2.0 (the "License");\nyou may not use this file except in compliance with the License.\nYou may obtain a copy of the License at\n\n    http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing, software\ndistributed under the License is distributed on an "AS IS" BASIS,\nWITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\nSee the License for the specific language governing permissions and\nlimitations under the License.\n*/\n\npackage kms\n\nimport (\n\t"context"\n\t"testing"\n\n\t"github.com/stretchr/testify/require"\n)\n\nfunc TestNewSecretsKMS(t *testing.T) {\n\tt.Parallel()\n\tsecrets := map[string]string{}\n\n\t// no passphrase in the secrets, should fail\n\tkms, err := newSecretsKMS(ProviderInitArgs{\n\t\tSecrets: secrets,\n\t})\n\trequire.Error(t, err)\n\trequire.Nil(t, kms)\n\n\t// set a passphrase and it should pass\n\tsecrets[encryptionPassphraseKey] = "plaintext encryption key"\n\tkms, err = newSecretsKMS(ProviderInitArgs{\n\t\tSecrets: secrets,\n\t})\n\trequire.NotNil(t, kms)\n\trequire.NoError(t, err)\n}\n\nfunc TestGenerateNonce(t *testing.T) {\n\tt.Parallel()\n\tsize := 64\n\tnonce, err := generateNonce(size)\n\trequire.Len(t, nonce, size)\n\trequire.NoError(t, err)\n}\n\nfunc TestGenerateCipher(t *testing.T) {\n\tt.Parallel()\n\t//nolint:gosec // this passphrase is intentionally hardcoded\n\tpassphrase := "my-cool-luks-passphrase"\n\tsalt := "unique-id-for-the-volume"\n\n\taead, err := generateCipher(passphrase, salt)\n\trequire.NoError(t, err)\n\trequire.NotNil(t, aead)\n}\n\nfunc TestInitSecretsMetadataKMS(t *testing.T) {\n\tt.Parallel()\n\targs := ProviderInitArgs{\n\t\tTenant:  "tenant",\n\t\tConfig:  nil,\n\t\tSecrets: map[string]string{},\n\t}\n\n\t// passphrase it not set, init should fail\n\tkms, err := initSecretsMetadataKMS(args)\n\trequire.Error(t, err)\n\trequire.Nil(t, kms)\n\n\t// set a passphrase to get a working KMS\n\targs.Secrets[encryptionPassphraseKey] = "my-passphrase-from-kubernetes"\n\n\tkms, err = initSecretsMetadataKMS(args)\n\trequire.NoError(t, err)\n\trequire.NotNil(t, kms)\n\trequire.Equal(t, DEKStoreMetadata, kms.RequiresDEKStore())\n}\n\nfunc TestWorkflowSecretsMetadataKMS(t *testing.T) {\n\tt.Parallel()\n\tsecrets := map[string]string{\n\t\tencryptionPassphraseKey: "my-passphrase-from-kubernetes",\n\t}\n\targs := ProviderInitArgs{\n\t\tTenant:  "tenant",\n\t\tConfig:  nil,\n\t\tSecrets: secrets,\n\t}\n\tvolumeID := "csi-vol-1b00f5f8-b1c1-11e9-8421-9243c1f659f0"\n\n\tkms, err := initSecretsMetadataKMS(args)\n\trequire.NoError(t, err)\n\trequire.NotNil(t, kms)\n\n\t// plainDEK is the (LUKS) passphrase for the volume\n\tplainDEK := "usually created with generateNewEncryptionPassphrase()"\n\n\tctx := context.TODO()\n\n\tencryptedDEK, err := kms.EncryptDEK(ctx, volumeID, plainDEK)\n\trequire.NoError(t, err)\n\trequire.NotEqual(t, "", encryptedDEK)\n\trequire.NotEqual(t, plainDEK, encryptedDEK)\n\n\t// with an incorrect volumeID, decrypting should fail\n\tdecryptedDEK, err := kms.DecryptDEK(ctx, "incorrect-volumeID", encryptedDEK)\n\trequire.Error(t, err)\n\trequire.Equal(t, "", decryptedDEK)\n\trequire.NotEqual(t, plainDEK, decryptedDEK)\n\n\t// with the right volumeID, decrypting should return the plainDEK\n\tdecryptedDEK, err = kms.DecryptDEK(ctx, volumeID, encryptedDEK)\n\trequire.NoError(t, err)\n\trequire.NotEqual(t, "", decryptedDEK)\n\trequire.Equal(t, plainDEK, decryptedDEK)\n}\n\nfunc TestSecretsMetadataKMSRegistered(t *testing.T) {\n\tt.Parallel()\n\t_, ok := kmsManager.providers[kmsTypeSecretsMetadata]\n\trequire.True(t, ok)\n}\n',
        }
